"use client";

import { useCallback, useRef, useState } from "react";
import { AUDIO_SAMPLE_RATE_INPUT, AUDIO_SAMPLE_RATE_OUTPUT } from "@/lib/constants";

/**
 * Manages microphone audio capture, Gemini audio playback, and real-time audio levels.
 *
 * @remarks
 * - Capture: Records at 16kHz 16-bit PCM mono, outputs base64 chunks.
 * - Playback: Decodes 24kHz PCM from Gemini and queues sequential playback.
 * - Audio Level: Exposed as a `useRef` to avoid 60fps re-renders.
 *   Components that need it (e.g. Avatar, AudioWaveform) should read
 *   `audioLevelRef.current` inside their own animation loops (useFrame / rAF).
 */
export function useAudioProcessor() {
  const [isMicActive, setIsMicActive] = useState(false);

  /**
   * Audio level as a ref ΓÇö NOT state ΓÇö to prevent 60fps re-renders.
   * Read this inside `useFrame` / `requestAnimationFrame`.
   * @see vercel-react-best-practices: rerender-use-ref-transient-values
   */
  const audioLevelRef = useRef(0);

  const streamRef = useRef<MediaStream | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animFrameRef = useRef<number>(0);
  const processorRef = useRef<ScriptProcessorNode | null>(null);

  // Playback refs
  const playbackCtxRef = useRef<AudioContext | null>(null);
  const playbackQueueRef = useRef<AudioBuffer[]>([]);
  const isPlayingRef = useRef(false);

  // ΓöÇΓöÇ Mic capture ΓöÇΓöÇ
  const startMic = useCallback(
    (onChunk: (base64: string) => void) => {
      (async () => {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({
            audio: {
              sampleRate: AUDIO_SAMPLE_RATE_INPUT,
              channelCount: 1,
              echoCancellation: true,
              noiseSuppression: true,
            },
          });
          streamRef.current = stream;

          const ctx = new AudioContext({ sampleRate: AUDIO_SAMPLE_RATE_INPUT });
          audioCtxRef.current = ctx;

          const source = ctx.createMediaStreamSource(stream);

          // Analyser for audio level (used for lip-sync)
          const analyser = ctx.createAnalyser();
          analyser.fftSize = 256;
          source.connect(analyser);
          analyserRef.current = analyser;

          // ScriptProcessor for PCM capture
          const processor = ctx.createScriptProcessor(4096, 1, 1);
          source.connect(processor);
          processor.connect(ctx.destination);
          processorRef.current = processor;

          processor.onaudioprocess = (e) => {
            const float32 = e.inputBuffer.getChannelData(0);
            // Float32 ΓåÆ Int16
            const int16 = new Int16Array(float32.length);
            for (let i = 0; i < float32.length; i++) {
              const s = Math.max(-1, Math.min(1, float32[i]));
              int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
            }
            // Int16 ΓåÆ base64
            const bytes = new Uint8Array(int16.buffer);
            let binary = "";
            for (let i = 0; i < bytes.length; i++) {
              binary += String.fromCharCode(bytes[i]);
            }
            onChunk(btoa(binary));
          };

          // rAF loop for audio level ΓåÆ ref (not state)
          const updateLevel = () => {
            if (!analyserRef.current) return;
            const data = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(data);
            const avg = data.reduce((sum, v) => sum + v, 0) / data.length;
            audioLevelRef.current = avg / 255;
            animFrameRef.current = requestAnimationFrame(updateLevel);
          };
          updateLevel();

          setIsMicActive(true);
        } catch (err) {
          console.error("[AudioProcessor] Mic error:", err);
        }
      })();
    },
    []
  );

  const stopMic = useCallback(() => {
    streamRef.current?.getTracks().forEach((t) => t.stop());
    audioCtxRef.current?.close();
    cancelAnimationFrame(animFrameRef.current);
    streamRef.current = null;
    audioCtxRef.current = null;
    analyserRef.current = null;
    processorRef.current = null;
    setIsMicActive(false);
    audioLevelRef.current = 0;
  }, []);

  // Drain the playback queue sequentially.
  // Plain function (not useCallback) since it accesses only refs.
  const drainQueue = () => {
    const ctx = playbackCtxRef.current;
    if (!ctx || playbackQueueRef.current.length === 0) {
      isPlayingRef.current = false;
      audioLevelRef.current = 0;
      return;
    }
    isPlayingRef.current = true;
    const buffer = playbackQueueRef.current.shift()!;
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.onended = () => drainQueue();
    source.start();
  };

  // ΓöÇΓöÇ Playback of Gemini audio ΓöÇΓöÇ
  const playAudioChunk = useCallback((base64: string) => {
    try {
      if (!playbackCtxRef.current) {
        playbackCtxRef.current = new AudioContext({
          sampleRate: AUDIO_SAMPLE_RATE_OUTPUT,
        });
      }
      const ctx = playbackCtxRef.current;

      // base64 ΓåÆ Int16 ΓåÆ Float32
      const binary = atob(base64);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) {
        bytes[i] = binary.charCodeAt(i);
      }
      const int16 = new Int16Array(bytes.buffer);
      const float32 = new Float32Array(int16.length);
      for (let i = 0; i < int16.length; i++) {
        float32[i] = int16[i] / 0x7fff;
      }

      const buffer = ctx.createBuffer(1, float32.length, AUDIO_SAMPLE_RATE_OUTPUT);
      buffer.copyToChannel(float32, 0);
      playbackQueueRef.current.push(buffer);

      // Update audio level ref for lip-sync during playback
      const rms = Math.sqrt(
        float32.reduce((sum, v) => sum + v * v, 0) / float32.length
      );
      audioLevelRef.current = Math.min(1, rms * 4);

      if (!isPlayingRef.current) {
        drainQueue();
      }
    } catch (err) {
      console.warn("[AudioProcessor] Playback error:", err);
    }
  }, []);

  return {
    isMicActive,
    audioLevelRef,
    startMic,
    stopMic,
    playAudioChunk,
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { GoogleGenAI, Modality, type Session, type LiveServerMessage } from "@google/genai";
import {
  GEMINI_MODEL,
  GEMINI_TOOLS,
  SYSTEM_PROMPT,
} from "@/lib/constants";

export type GeminiStatus = "disconnected" | "connecting" | "connected" | "error";

export interface ToolCallPayload {
  name: string;
  args: Record<string, string>;
  id?: string;
}

export interface UseGeminiLiveReturn {
  status: GeminiStatus;
  connect: () => void;
  disconnect: () => void;
  sendVideoFrame: (base64: string) => void;
  sendAudioChunk: (base64: string) => void;
  sendText: (text: string) => void;
  onAudioData: React.RefObject<((b64: string) => void) | null>;
  onToolCall: React.RefObject<((tc: ToolCallPayload) => void) | null>;
  onTranscript: React.RefObject<((text: string) => void) | null>;
  errorMessage: string | null;
}

/**
 * Manages the connection to the Gemini Multimodal Live API
 * using the official @google/genai SDK.
 *
 * @param apiKey - Gemini API key from environment
 * @returns Connection controls, send functions, and callback refs
 *
 * @remarks
 * Callback refs (`onAudioData`, `onToolCall`, `onTranscript`) are used
 * instead of callback props to avoid re-renders on every audio chunk.
 * @see vercel-react-best-practices: advanced-event-handler-refs
 */
export function useGeminiLive(apiKey: string): UseGeminiLiveReturn {
  const sessionRef = useRef<Session | null>(null);
  const [status, setStatus] = useState<GeminiStatus>("disconnected");
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  // Use a ref to track latest status to avoid stale closures in callbacks
  const statusRef = useRef<GeminiStatus>(status);
  useEffect(() => {
    statusRef.current = status;
  }, [status]);

  // Callback refs ΓÇö avoids re-rendering on every audio chunk
  const onAudioData = useRef<((b64: string) => void) | null>(null);
  const onToolCall = useRef<((tc: ToolCallPayload) => void) | null>(null);
  const onTranscript = useRef<((text: string) => void) | null>(null);

  // SDK client ΓÇö initialized once per apiKey
  const clientRef = useRef<GoogleGenAI | null>(null);
  useEffect(() => {
    clientRef.current = new GoogleGenAI({ apiKey });
  }, [apiKey]);

  const disconnect = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setStatus("disconnected");
  }, []);

  const connect = useCallback(() => {
    if (sessionRef.current) disconnect();
    if (!clientRef.current) {
      setErrorMessage("SDK client not initialized. Check API key.");
      setStatus("error");
      return;
    }

    setStatus("connecting");
    setErrorMessage(null);

    const ai = clientRef.current;

    // Handle incoming messages from the Live API
    const handleMessage = (message: LiveServerMessage) => {
      try {
        // Server content (audio response and/or text)
        if (message.serverContent) {
          // Handle interruption ΓÇö clear any pending audio
          if (message.serverContent.interrupted) {
            console.log("[GeminiLive] Interrupted by user speech.");
            return;
          }

          const parts = message.serverContent.modelTurn?.parts;
          if (parts) {
            for (const part of parts) {
              if (part.inlineData?.mimeType?.startsWith("audio/")) {
                onAudioData.current?.(part.inlineData.data as string);
              }
              if (part.text) {
                onTranscript.current?.(part.text);
              }
            }
          }
        }

        // Tool call response
        if (message.toolCall) {
          const calls = message.toolCall.functionCalls;
          if (calls) {
            for (const call of calls) {
              console.log("[GeminiLive] Tool call:", call.name, call.args);
              onToolCall.current?.({
                name: call.name || "",
                args: (call.args as Record<string, string>) || {},
                id: call.id,
              });

              // Send tool response back via SDK
              sessionRef.current?.sendToolResponse({
                functionResponses: [
                  {
                    id: call.id || "",
                    name: call.name || "",
                    response: { result: "ok" },
                  },
                ],
              });
            }
          }
        }
      } catch (err) {
        console.warn("[GeminiLive] Failed to handle message:", err);
      }
    };

    // Connect using the official SDK
    ai.live
      .connect({
        model: GEMINI_MODEL,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: {
                voiceName: "Aoede",
              },
            },
          },
          systemInstruction: SYSTEM_PROMPT,
          tools: GEMINI_TOOLS,
        },
        callbacks: {
          onopen: () => {
            console.log("[GeminiLive] Connected via SDK.");
            setStatus("connected");
          },
          onmessage: handleMessage,
          onerror: (e: ErrorEvent) => {
            console.error("[GeminiLive] SDK error:", e.message);
            setErrorMessage(
              `Connection error: ${e.message || "Check API Key and network."}`
            );
            setStatus("error");
          },
          onclose: (e: CloseEvent) => {
            console.log("[GeminiLive] Session closed:", e.code, e.reason);
            if (statusRef.current !== "disconnected") {
              setStatus("disconnected");
            }
          },
        },
      })
      .then((session) => {
        sessionRef.current = session;
        console.log("[GeminiLive] Session established.");
      })
      .catch((err) => {
        console.error("[GeminiLive] Failed to connect:", err);
        setErrorMessage(
          `Failed to connect: ${err instanceof Error ? err.message : String(err)}`
        );
        setStatus("error");
      });
  }, [apiKey, disconnect]);

  // Send a base64 JPEG video frame
  const sendVideoFrame = useCallback((base64Image: string) => {
    sessionRef.current?.sendRealtimeInput({
      video: {
        data: base64Image,
        mimeType: "image/jpeg",
      },
    });
  }, []);

  // Send a base64 PCM audio chunk
  const sendAudioChunk = useCallback((base64Audio: string) => {
    sessionRef.current?.sendRealtimeInput({
      audio: {
        data: base64Audio,
        mimeType: "audio/pcm;rate=16000",
      },
    });
  }, []);

  // Send a text message
  const sendText = useCallback((text: string) => {
    sessionRef.current?.sendClientContent({
      turns: [{ role: "user", parts: [{ text }] }],
      turnComplete: true,
    });
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      sessionRef.current?.close();
    };
  }, []);

  return {
    status,
    connect,
    disconnect,
    sendVideoFrame,
    sendAudioChunk,
    sendText,
    onAudioData,
    onToolCall,
    onTranscript,
    errorMessage,
  };
}

